query partnerDetails($id: String, $slug: String, $planId: String, $selectedPlanId: String, $returnProfessionalPhotos: Boolean, $enablePartnerSummary: Boolean!, $enableTranslatedPartnerAbout: Boolean!, $enablePartnerIncludedInYourPlanTag: Boolean!, $enablePartnerPageProductRestrictions: Boolean!, $filters: PartnerFiltersInput!, $latitude: Float, $longitude: Float) {
  classScheduleButton(input: {partnerId: $id, slug: $slug}) {
    primaryAction {
      label {
        key
        __typename
      }
      route {
        name
        params
        __typename
      }
      __typename
    }
    shouldDisplayButton
    __typename
  }
  partner(filters: $filters) {
    id
    name
    slug
    type
    description @include(if: $enableTranslatedPartnerAbout) {
      ...PartnerTranslatedFieldFragment
      __typename
    }
    importantInformation @include(if: $enableTranslatedPartnerAbout) {
      ...PartnerTranslatedFieldFragment
      __typename
    }
    about {
      description
      goodToKnow
      __typename
    }
    tags {
      id
      slug
      translationKey
      defaultValue
      __typename
    }
    rating {
      count
      average
      histogram {
        score
        count
        __typename
      }
      __typename
    }
    reviews @include(if: $enablePartnerSummary) {
      reviewsSummary {
        id
        summary
        language
        userFeedback {
          id
          isPositive
          __typename
        }
        __typename
      }
      __typename
    }
    userPlanAvailability(latitude: $latitude, longitude: $longitude) @include(if: $enablePartnerIncludedInYourPlanTag) {
      status
      availableFrom {
        id
        name
        usageType
        __typename
      }
      conditions {
        offPeak
        __typename
      }
      __typename
    }
    products(latitude: $latitude, longitude: $longitude) @include(if: $enablePartnerPageProductRestrictions) {
      ...PartnerProductRestrictionsFragment
      __typename
    }
    __typename
  }
  partnerDetails(
    partnerId: $id
    slug: $slug
    planId: $planId
    exploreSelectedPlanId: $selectedPlanId
    returnProfessionalPhotos: $returnProfessionalPhotos
  ) {
    ... on PartnerPage {
      favorited
      details {
        id
        slug
        shareUrl
        location {
          latitude
          longitude
          __typename
        }
        header {
          title
          type
          logo
          exclusivity {
            label {
              key
              params
              __typename
            }
            type
            __typename
          }
          rating {
            count
            average
            __typename
          }
          __typename
        }
        contact {
          address {
            fullAddress
            mapsUrl
            __typename
          }
          phone {
            mask
            number
            __typename
          }
          website {
            authority
            link
            __typename
          }
          __typename
        }
        gallery {
          id
          uri
          __typename
        }
        options {
          about {
            title {
              key
              params
              __typename
            }
            subtitle
            defaultSubtitle {
              key
              params
              __typename
            }
            __typename
          }
          openingHour {
            type
            title {
              key
              params
              __typename
            }
            subtitle {
              key
              params
              __typename
            }
            __typename
          }
          partnerProducts {
            availability
